#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=20005;
struct node
{
	int v,w;
};
vector<node> g[N];
int n,cnt[N],dp[N],vis[N],fa[N],son[N],ans,root,sum;
//f[u] 记录以u为根的最大子树的大小 （包含u的父亲） 
//son[u] 记录u的子树大小 
void dfs(int u,int f)
{
	cnt[dp[u]]++;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i].v;
		if(v==f||vis[v]) continue;
		dp[v]=(dp[u]+g[u][i].w)%3;
		dfs(v,u);
	}
}
int fun(int u,int num)
{
	cnt[0]=cnt[1]=cnt[2]=0;
	dp[u]=num;
	dfs(u,0);
	return cnt[1]*cnt[2]*2+cnt[0]*cnt[0];
	//上一行解释一下 第一个“cnt[1]*cnt[2]*2”虽然有的时候2个点在根节点的一个子树上 2个点的dis应该是做减法 但是后面把这种情况减去了
	//第2个“cnt[0]*cnt[0]”不*2是因为本来就多算了一倍 2个数 1把2算进去了 2也把1算进去了 
}
void getroot(int u,int f)//求连通块的重心 
{
	son[u]=1;
	fa[u]=0;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i].v;
		if(v==f) continue;
		if(vis[v]) continue;
		getroot(v,u);
		son[u]+=son[v];
		fa[u]=max(fa[u],son[v]);
	}
	fa[u]=max(fa[u],sum-son[u]);
	if(fa[u]<fa[root]) root=u;
}
void solve(int u)//点分治 
{
	ans+=fun(u,0);
	vis[u]=1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i].v;
		if(vis[v]) continue;
		ans-=fun(v,g[u][i].w);// 再减去多余的 
		root=0;
		sum=son[v];
		getroot(v,0);
		solve(root);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<n;i++)
	{
		int u,v,w;
		cin>>u>>v>>w;
		w%=3;
		g[u].push_back(node{v,w});
		g[v].push_back(node{u,w});
	}
	sum=fa[0]=n;
	getroot(1,0);
	solve(root);
	int tmp=__gcd(ans,n*n);
	cout<<ans/tmp<<"/"<<n*n/tmp;
	return 0;
}
